function solve(s) {
    const n = s.length;
    const totalZeros = s.split('0').length - 1;
    const totalOnes = n - totalZeros;

    // Helper function to find the maximum length of a balanced subarray
    // in a given string t.
    const maxBalancedSubarray = (t) => {
        const m = t.length;
        let maxLen = 0;
        // Use a map to store the first index where a certain balance (count0 - count1) is seen.
        // balance_map[balance] = index
        const balanceMap = new Map();
        balanceMap.set(0, -1); // A balance of 0 is seen before the string starts (at index -1)
        let currentBalance = 0;

        for (let j = 0; j < m; j++) {
            if (t[j] === '0') {
                currentBalance++;
            } else {
                currentBalance--;
            }

            if (balanceMap.has(currentBalance)) {
                const i = balanceMap.get(currentBalance) + 1;
                maxLen = Math.max(maxLen, j - balanceMap.get(currentBalance));
            } else {
                balanceMap.set(currentBalance, j);
            }
        }
        return maxLen;
    };

    let maxOverallLength = 0;

    // Case 1: No swap (or swapping identical characters)
    maxOverallLength = Math.max(maxOverallLength, maxBalancedSubarray(s));

    // Case 2: Try every possible single swap (i, j) where i < j
