        for (let j = i + 1; j < n; j++) {
            if (s[i] === s[j]) continue; // Swapping identical characters is covered by Case 1

            // Create the new string s_prime after swapping s[i] and s[j]
            const s_prime_array = s.split('');
            [s_prime_array[i], s_prime_array[j]] = [s_prime_array[j], s_prime_array[i]];
            const s_prime = s_prime_array.join('');

            // Find the max balanced subarray in s_prime
            const currentMax = maxBalancedSubarray(s_prime);
            maxOverallLength = Math.max(maxOverallLength, currentMax);
        }
    }

    // Edge case: If n=0, result is 0. The problem constraints say 1 <= n.
    // If no balanced subarray of length > 0 can be found, the result is 0 (empty subarray).
    return maxOverallLength;
}

